        public override string ToString()
        {
            var sb = new StringBuilder(100);
            var m = new OrderUpdateValuesMessage();
            m.WrapForDecode(_buffer, _offset, _actingBlockLength, _actingVersion);
            m.BuildString(sb);
            return sb.ToString();
        }

        internal void BuildString(StringBuilder builder)
        {
            if (_buffer == null)
            {
                throw new ArgumentNullException("_buffer");
            }

            int originalLimit = this.Limit;
            this.Limit = _offset + _actingBlockLength;
            builder.Append("[OrderUpdateValuesMessage](sbeTemplateId=");
            builder.Append(OrderUpdateValuesMessage.TemplateId);
            builder.Append("|sbeSchemaId=");
            builder.Append(OrderUpdateValuesMessage.SchemaId);
            builder.Append("|sbeSchemaVersion=");
            if (_parentMessage._actingVersion != OrderUpdateValuesMessage.SchemaVersion)
            {
                builder.Append(_parentMessage._actingVersion);
                builder.Append('/');
            }
            builder.Append(OrderUpdateValuesMessage.SchemaVersion);
            builder.Append("|sbeBlockLength=");
            if (_actingBlockLength != OrderUpdateValuesMessage.BlockLength)
            {
                builder.Append(_actingBlockLength);
                builder.Append('/');
            }
            builder.Append(OrderUpdateValuesMessage.BlockLength);
            builder.Append("):");

            builder.Append("ClearOrderIdSet=");
            builder.Append(this.ClearOrderIdSet);
            builder.Append('|');
            builder.Append("IsCancelEnabled=");
            builder.Append(this.IsCancelEnabled);
            builder.Append('|');
            builder.Append("IsModifyEnabled=");
            builder.Append(this.IsModifyEnabled);
            builder.Append('|');
            builder.Append("IsSubmitEnabled=");
            builder.Append(this.IsSubmitEnabled);
            builder.Append('|');
            builder.Append("IsMainOrder=");
            builder.Append(this.IsMainOrder);
            builder.Append('|');
            builder.Append("IsContraOrder=");
            builder.Append(this.IsContraOrder);
            builder.Append('|');
            builder.Append("IsHedgeOrder=");
            builder.Append(this.IsHedgeOrder);
            builder.Append('|');
            builder.Append("IsLooping=");
            builder.Append(this.IsLooping);
            builder.Append('|');
            builder.Append("RequiresManualIntervention=");
            builder.Append(this.RequiresManualIntervention);
            builder.Append('|');
            builder.Append("Filled=");
            builder.Append(this.Filled);
            builder.Append('|');
            builder.Append("CumQuantity=");
            builder.Append(this.CumQuantity);
            builder.Append('|');
            builder.Append("LastQuantity=");
            builder.Append(this.LastQuantity);
            builder.Append('|');
            builder.Append("LeavesQuantity=");
            builder.Append(this.LeavesQuantity);
            builder.Append('|');
            builder.Append("StatusMode=");
            builder.Append(this.StatusMode);
            builder.Append('|');
            builder.Append("OrderStatus=");
            builder.Append(this.OrderStatus);
            builder.Append('|');
            builder.Append("LastUpdateTime=");
            builder.Append(this.LastUpdateTime);
            builder.Append('|');
            builder.Append("LastPrice=");
            builder.Append(this.LastPrice);
            builder.Append('|');
            builder.Append("AveragePrice=");
            builder.Append(this.AveragePrice);
            builder.Append('|');
            builder.Append("AveragePriceAfterFees=");
            builder.Append(this.AveragePriceAfterFees);
            builder.Append('|');
            builder.Append("Status=");
            builder.Append("'");
            for (int i = 0; i < StatusLength && this.GetStatus(i) > 0; ++i)
            {
                builder.Append((char)this.GetStatus(i));
            }
            builder.Append("'");
            builder.Append('|');
            builder.Append("OrderId=");
            builder.Append("'");
            for (int i = 0; i < OrderIdLength && this.GetOrderId(i) > 0; ++i)
            {
                builder.Append((char)this.GetOrderId(i));
            }
            builder.Append("'");
            builder.Append('|');
            builder.Append("LocalOrderId=");
            builder.Append("'");
            for (int i = 0; i < LocalOrderIdLength && this.GetLocalOrderId(i) > 0; ++i)
            {
                builder.Append((char)this.GetLocalOrderId(i));
            }
            builder.Append("'");
            builder.Append('|');
            builder.Append("ParentLocalOrderId=");
            builder.Append("'");
            for (int i = 0; i < ParentLocalOrderIdLength && this.GetParentLocalOrderId(i) > 0; ++i)
            {
                builder.Append((char)this.GetParentLocalOrderId(i));
            }
            builder.Append("'");
            builder.Append('|');
            builder.Append("OriginalOrderId=");
            builder.Append("'");
            for (int i = 0; i < OriginalOrderIdLength && this.GetOriginalOrderId(i) > 0; ++i)
            {
                builder.Append((char)this.GetOriginalOrderId(i));
            }
            builder.Append("'");
            builder.Append('|');
            builder.Append("Message=");
            builder.Append("'");
            for (int i = 0; i < MessageLength && this.GetMessage(i) > 0; ++i)
            {
                builder.Append((char)this.GetMessage(i));
            }
            builder.Append("'");
            builder.Append('|');
            builder.Append("UnderlyingMidPrice=");
