            builder.Append('|');
            builder.Append("Price=");
            builder.Append(this.Price);
            builder.Append('|');
            builder.Append("AutomationRunning=");
            builder.Append(this.AutomationRunning);
            builder.Append('|');
            builder.Append("ContraTrader=");
